const mensaje = $('Variables3').first().json.mensaje || "";

function limpiar(texto) {
  return String(texto || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\*/g, "")
    .replace(/[^\w\sñ]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function esProducto(row) {
  const nombre = limpiar(row.nombre);

  if (!nombre) return false;

  const excluidos = [
    "martes",
    "precio kg",
    "precio",
    "verduras y hortalizas",
    "frutas frescas",
    "tuberculos raices y platanos",
    "variedad predominante",
    "variacion porcentual",
    "no disponible"
  ];

  if (excluidos.some(e => nombre.includes(e))) return false;

  return row.precio_centroabastos !== null || row.precio_corabastos !== null;
}

const productos = $input.all()
  .map((item, index) => ({
    x: index,
    nombre: item.json.nombre
  }))
  .filter(item => {
    const row = $input.all()[item.x].json;
    return esProducto(row);
  });

return [
  {
    json: {
      mensaje_usuario: mensaje,
      productos: productos,
      instancia_ws: $('Variables3').first().json.instancia_ws,
      telefono: $('Variables3').first().json.telefono,
      id_mensaje: $('Variables3').first().json.id_mensaje
    }
  }
];

// ======================================================
// CODE NODE: Generar URLs SIPSA candidatas
// Objetivo:
// - Si el usuario NO pide fecha: buscar la base SIPSA más reciente disponible.
// - Si el usuario pide fecha: buscar exactamente esa fecha.
// Soporta:
//   hoy
//   ayer
//   antes de ayer / anteayer / antier
//   hace 2 días / hace dos días
//   martes 16
//   del miércoles / miércoles pasado
//   10/06/2026
//   10 de junio
// ======================================================

// ---------- 1. Traer variables ----------
const entrada = $input.first()?.json || {};
const variables = $("Variables3").first().json || {};

const instancia_ws = entrada.instancia_ws || variables.instancia_ws || "";
const telefono = entrada.telefono || variables.telefono || "";
const id_mensaje = entrada.id_mensaje || variables.id_mensaje || "";

const mensaje_usuario =
  entrada.mensaje_usuario ||
  entrada.mensaje ||
  variables.mensaje ||
  "";

// ---------- 2. Configuración ----------
const maxDiasAtras = 20;

const mesesDane = [
  "ene", "feb", "mar", "abr", "may", "jun",
  "jul", "ago", "sep", "oct", "nov", "dic"
];

const mesesTexto = {
  "enero": 1,
  "febrero": 2,
  "marzo": 3,
  "abril": 4,
  "mayo": 5,
  "junio": 6,
  "julio": 7,
  "agosto": 8,
  "septiembre": 9,
  "setiembre": 9,
  "octubre": 10,
  "noviembre": 11,
  "diciembre": 12
};

const numerosTexto = {
  "un": 1,
  "uno": 1,
  "una": 1,
  "dos": 2,
  "tres": 3,
  "cuatro": 4,
  "cinco": 5,
  "seis": 6,
  "siete": 7,
  "ocho": 8,
  "nueve": 9,
  "diez": 10,
  "once": 11,
  "doce": 12,
  "trece": 13,
  "catorce": 14,
  "quince": 15,
  "dieciseis": 16,
  "dieciséis": 16,
  "diecisiete": 17,
  "dieciocho": 18,
  "diecinueve": 19,
  "veinte": 20,
  "veintiuno": 21,
  "veintidos": 22,
  "veintidós": 22,
  "veintitres": 23,
  "veintitrés": 23,
  "veinticuatro": 24,
  "veinticinco": 25,
  "veintiseis": 26,
  "veintiséis": 26,
  "veintisiete": 27,
  "veintiocho": 28,
  "veintinueve": 29,
  "treinta": 30
};

const diasSemanaNumero = {
  "domingo": 0,
  "lunes": 1,
  "martes": 2,
  "miercoles": 3,
  "miércoles": 3,
  "jueves": 4,
  "viernes": 5,
  "sabado": 6,
  "sábado": 6
};

// ---------- 3. Funciones auxiliares ----------
function limpiarTexto(texto) {
  return String(texto || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\w\sñ\/\-\.]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function capitalizar(texto) {
  texto = String(texto || "");
  return texto.charAt(0).toUpperCase() + texto.slice(1);
}

function obtenerFechaActualColombia() {
  const partes = new Intl.DateTimeFormat("es-CO", {
    timeZone: "America/Bogota",
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(new Date());

  return {
    dia: Number(partes.find(p => p.type === "day").value),
    mes: Number(partes.find(p => p.type === "month").value),
    anio: Number(partes.find(p => p.type === "year").value)
  };
}

function fechaUTCDesdePartes(anio, mes, dia) {
  return new Date(Date.UTC(anio, mes - 1, dia));
}

function restarDias(fechaUTC, dias) {
  return new Date(fechaUTC.getTime() - dias * 24 * 60 * 60 * 1000);
}

function obtenerPartesDesdeUTC(fechaUTC) {
  const dia = fechaUTC.getUTCDate();
  const mes = fechaUTC.getUTCMonth() + 1;
  const anio = fechaUTC.getUTCFullYear();

  const diaConCero = String(dia).padStart(2, "0");
  const diaSinCero = String(dia);
  const mesDane = mesesDane[mes - 1];

  const diaSemana = new Intl.DateTimeFormat("es-CO", {
    weekday: "long",
    timeZone: "UTC"
  }).format(fechaUTC).toLowerCase();

  const mesLargo = new Intl.DateTimeFormat("es-CO", {
    month: "long",
    timeZone: "UTC"
  }).format(fechaUTC).toLowerCase();

  return {
    dia,
    mes,
    anio,
    diaConCero,
    diaSinCero,
    mesDane,
    diaSemana,
    mesLargo
  };
}

function esFinDeSemana(diaSemana) {
  return diaSemana.includes("sábado") ||
         diaSemana.includes("sabado") ||
         diaSemana.includes("domingo");
}

function fechaISODesdeUTC(fechaUTC) {
  const anio = fechaUTC.getUTCFullYear();
  const mes = String(fechaUTC.getUTCMonth() + 1).padStart(2, "0");
  const dia = String(fechaUTC.getUTCDate()).padStart(2, "0");
  return `${anio}-${mes}-${dia}`;
}

function fechaLegibleLargaDesdeUTC(fechaUTC) {
  const partes = obtenerPartesDesdeUTC(fechaUTC);
  return `${capitalizar(partes.diaSemana)} ${partes.dia} de ${partes.mesLargo} de ${partes.anio}`;
}

function fechaValida(anio, mes, dia) {
  const f = fechaUTCDesdePartes(anio, mes, dia);
  return (
    f.getUTCFullYear() === anio &&
    f.getUTCMonth() + 1 === mes &&
    f.getUTCDate() === dia
  );
}

function diaSemanaUTC(fechaUTC) {
  return fechaUTC.getUTCDay();
}

function encontrarUltimoDiaSemana(fechaBaseUTC, diaObjetivo, forzarPasado = false) {
  const hoySemana = diaSemanaUTC(fechaBaseUTC);

  let diferencia = hoySemana - diaObjetivo;

  if (diferencia < 0) {
    diferencia += 7;
  }

  if (forzarPasado && diferencia === 0) {
    diferencia = 7;
  }

  return restarDias(fechaBaseUTC, diferencia);
}

// ---------- 4. Detectar fecha solicitada ----------
function detectarFechaSolicitada(mensajeUsuario, fechaBaseUTC) {
  const mensaje = limpiarTexto(mensajeUsuario);
  const hoyUTC = fechaBaseUTC;
  const anioActual = hoyUTC.getUTCFullYear();
  const mesActual = hoyUTC.getUTCMonth() + 1;

  // 1. Antes de ayer / anteayer / antier
  // IMPORTANTE: esto va antes que "ayer", para evitar interpretar "antes de ayer" como "ayer".
  if (
    /\bantes\s+de\s+ayer\b/.test(mensaje) ||
    /\banteayer\b/.test(mensaje) ||
    /\bantier\b/.test(mensaje)
  ) {
    return {
      tiene_fecha: true,
      tipo_fecha: "anteayer",
      descripcion_fecha: "anteayer",
      offset_dias: 2,
      fechaUTC: restarDias(hoyUTC, 2)
    };
  }

  // 2. Hoy
  if (/\bhoy\b/.test(mensaje)) {
    return {
      tiene_fecha: true,
      tipo_fecha: "hoy",
      descripcion_fecha: "hoy",
      offset_dias: 0,
      fechaUTC: hoyUTC
    };
  }

  // 3. Ayer
  if (/\bayer\b/.test(mensaje)) {
    return {
      tiene_fecha: true,
      tipo_fecha: "ayer",
      descripcion_fecha: "ayer",
      offset_dias: 1,
      fechaUTC: restarDias(hoyUTC, 1)
    };
  }

  // 4. Hace X días
  const matchHaceDias = mensaje.match(
    /\bhace\s+(\d+|un|uno|una|dos|tres|cuatro|cinco|seis|siete|ocho|nueve|diez|once|doce|trece|catorce|quince|dieciseis|diecisiete|dieciocho|diecinueve|veinte|veintiuno|veintidos|veintitres|veinticuatro|veinticinco|veintiseis|veintisiete|veintiocho|veintinueve|treinta)\s+dias?\b/
  );

  if (matchHaceDias) {
    const valor = matchHaceDias[1];
    const dias = /^\d+$/.test(valor) ? Number(valor) : numerosTexto[valor];

    if (Number.isFinite(dias) && dias >= 0) {
      return {
        tiene_fecha: true,
        tipo_fecha: "hace_dias",
        descripcion_fecha: `hace ${dias} día${dias === 1 ? "" : "s"}`,
        offset_dias: dias,
        fechaUTC: restarDias(hoyUTC, dias)
      };
    }
  }

  // 5. Fecha numérica: 10/06/2026, 10-06-2026, 10.06.2026 o 10/06
  const matchNumerica = mensaje.match(/(?:^|\D)(\d{1,2})[\/\-\.](\d{1,2})(?:[\/\-\.](\d{2,4}))?(?:\D|$)/);

  if (matchNumerica) {
    const dia = Number(matchNumerica[1]);
    const mes = Number(matchNumerica[2]);

    let anio = matchNumerica[3]
      ? Number(matchNumerica[3])
      : anioActual;

    if (anio < 100) {
      anio = 2000 + anio;
    }

    if (fechaValida(anio, mes, dia)) {
      return {
        tiene_fecha: true,
        tipo_fecha: "fecha_numerica",
        descripcion_fecha: `${String(dia).padStart(2, "0")}/${String(mes).padStart(2, "0")}/${anio}`,
        offset_dias: null,
        fechaUTC: fechaUTCDesdePartes(anio, mes, dia)
      };
    }
  }

  // 6. Fecha textual: 10 de junio, 10 junio, 10 de junio de 2026
  const matchTexto = mensaje.match(/\b(\d{1,2})\s+(?:de\s+)?(enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|setiembre|octubre|noviembre|diciembre)(?:\s+de)?\s*(\d{4})?\b/);

  if (matchTexto) {
    const dia = Number(matchTexto[1]);
    const mesTexto = matchTexto[2];
    const mes = mesesTexto[mesTexto];
    const anio = matchTexto[3] ? Number(matchTexto[3]) : anioActual;

    if (fechaValida(anio, mes, dia)) {
      return {
        tiene_fecha: true,
        tipo_fecha: "fecha_textual",
        descripcion_fecha: `${dia} de ${mesTexto} de ${anio}`,
        offset_dias: null,
        fechaUTC: fechaUTCDesdePartes(anio, mes, dia)
      };
    }
  }

  // 7. Día de semana con número: martes 16, el martes 16
  const matchDiaSemanaConNumero = mensaje.match(/\b(lunes|martes|miercoles|miércoles|jueves|viernes|sabado|sábado|domingo)\s+(\d{1,2})(?:\s+(?:de\s+)?(enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|setiembre|octubre|noviembre|diciembre))?(?:\s+de)?\s*(\d{4})?\b/);

  if (matchDiaSemanaConNumero) {
    const diaSemanaTexto = matchDiaSemanaConNumero[1];
    const dia = Number(matchDiaSemanaConNumero[2]);
    const mes = matchDiaSemanaConNumero[3]
      ? mesesTexto[matchDiaSemanaConNumero[3]]
      : mesActual;
    const anio = matchDiaSemanaConNumero[4]
      ? Number(matchDiaSemanaConNumero[4])
      : anioActual;

    let fecha = fechaUTCDesdePartes(anio, mes, dia);

    // Si la fecha resultante queda en el futuro y no se especificó mes,
    // asumir que era del mes anterior.
    if (!matchDiaSemanaConNumero[3] && fecha.getTime() > hoyUTC.getTime()) {
      fecha = fechaUTCDesdePartes(anio, mes - 1, dia);
    }

    if (fechaValida(fecha.getUTCFullYear(), fecha.getUTCMonth() + 1, fecha.getUTCDate())) {
      return {
        tiene_fecha: true,
        tipo_fecha: "dia_semana_con_numero",
        descripcion_fecha: `${diaSemanaTexto} ${dia}`,
        offset_dias: null,
        fechaUTC: fecha
      };
    }
  }

  // 8. Día de semana solamente: del miércoles, miércoles pasado, el miércoles
  const matchDiaSemana = mensaje.match(/\b(lunes|martes|miercoles|miércoles|jueves|viernes|sabado|sábado|domingo)\b/);

  if (matchDiaSemana) {
    const diaSemanaTexto = matchDiaSemana[1];
    const diaObjetivo = diasSemanaNumero[diaSemanaTexto];

    if (diaObjetivo !== undefined) {
      const forzarPasado = mensaje.includes("pasado");
      const fecha = encontrarUltimoDiaSemana(hoyUTC, diaObjetivo, forzarPasado);

      return {
        tiene_fecha: true,
        tipo_fecha: "dia_semana",
        descripcion_fecha: forzarPasado ? `${diaSemanaTexto} pasado` : diaSemanaTexto,
        offset_dias: null,
        fechaUTC: fecha
      };
    }
  }

  return {
    tiene_fecha: false,
    tipo_fecha: "sin_fecha",
    descripcion_fecha: null,
    offset_dias: null,
    fechaUTC: null
  };
}

// ---------- 5. Crear candidatos de URL para una fecha ----------
function crearCandidatosParaFecha(fechaUTC, opciones) {
  const partes = obtenerPartesDesdeUTC(fechaUTC);

  const fechaDaneSinCero = `${partes.diaSinCero}${partes.mesDane}${partes.anio}`;
  const fechaDaneConCero = `${partes.diaConCero}${partes.mesDane}${partes.anio}`;

  const fechaLegible = `${partes.diaConCero}/${String(partes.mes).padStart(2, "0")}/${partes.anio}`;
  const fechaLegibleLarga = fechaLegibleLargaDesdeUTC(fechaUTC);

  const candidatos = [];

  candidatos.push({
    fecha_dane: fechaDaneSinCero,
    fecha_legible: fechaLegible,
    fecha_legible_larga: fechaLegibleLarga,
    fecha_objetivo_iso: fechaISODesdeUTC(fechaUTC),
    dia_semana: partes.diaSemana,
    url_sipsa: `https://www.dane.gov.co/files/operaciones/SIPSA/anex-SIPSADiario-${fechaDaneSinCero}.xlsx`,
    ...opciones
  });

  if (fechaDaneConCero !== fechaDaneSinCero) {
    candidatos.push({
      fecha_dane: fechaDaneConCero,
      fecha_legible: fechaLegible,
      fecha_legible_larga: fechaLegibleLarga,
      fecha_objetivo_iso: fechaISODesdeUTC(fechaUTC),
      dia_semana: partes.diaSemana,
      url_sipsa: `https://www.dane.gov.co/files/operaciones/SIPSA/anex-SIPSADiario-${fechaDaneConCero}.xlsx`,
      ...opciones
    });
  }

  return candidatos;
}

// ---------- 6. Fecha actual Colombia ----------
const hoyColombia = obtenerFechaActualColombia();

const fechaBaseUTC = fechaUTCDesdePartes(
  hoyColombia.anio,
  hoyColombia.mes,
  hoyColombia.dia
);

// ---------- 7. Detectar fecha solicitada ----------
const fechaSolicitada = detectarFechaSolicitada(mensaje_usuario, fechaBaseUTC);

let candidatos = [];

// Caso A: usuario pidió fecha específica
if (fechaSolicitada.tiene_fecha) {
  candidatos = crearCandidatosParaFecha(fechaSolicitada.fechaUTC, {
    modo_busqueda_fecha: "fecha_especifica",
    fecha_solicitada: true,
    tipo_fecha_solicitada: fechaSolicitada.tipo_fecha,
    descripcion_fecha_solicitada: fechaSolicitada.descripcion_fecha,
    offset_dias_solicitado: fechaSolicitada.offset_dias,
    instancia_ws,
    telefono,
    id_mensaje,
    mensaje_usuario
  });
}

// Caso B: usuario NO pidió fecha, buscar base más reciente
else {
  for (let offset = 0; offset <= maxDiasAtras; offset++) {
    const fechaCandidataUTC = restarDias(fechaBaseUTC, offset);
    const partes = obtenerPartesDesdeUTC(fechaCandidataUTC);

    if (esFinDeSemana(partes.diaSemana)) {
      continue;
    }

    const nuevos = crearCandidatosParaFecha(fechaCandidataUTC, {
      modo_busqueda_fecha: "mas_reciente",
      fecha_solicitada: false,
      tipo_fecha_solicitada: null,
      descripcion_fecha_solicitada: null,
      offset_dias_solicitado: offset,
      es_fecha_hoy: offset === 0,
      instancia_ws,
      telefono,
      id_mensaje,
      mensaje_usuario
    });

    candidatos.push(...nuevos);
  }
}

// ---------- 8. Salida ----------
return candidatos.map((candidato, index) => ({
  json: {
    intento: index + 1,
    ...candidato
  }
}));

