// ======================================================
// CODE NODE: Obtener precios reales y crear respuesta_base
// Este nodo debe ir DESPUÉS del Agente IA normalizador
// Incluye:
// - Precio actual en negrilla para WhatsApp
// - Variación en pesos usando Var % de SIPSA
// - Corrige Var % cuando Excel entrega 0.04 como 4%
// - Emojis para variación
// - Sin mostrar porcentajes ni signos al usuario
// - Regiones por mercado
// - Artículos: del banano, de la papa, de la mora, etc.
// ======================================================

// ---------- 1. Obtener salida del Agente IA ----------
const entrada = $input.first()?.json || {};

let normalizado = null;

if (
  entrada.encontrado !== undefined &&
  entrada.x !== undefined
) {
  normalizado = entrada;
} else {
  let raw = entrada.output 
    || entrada.text 
    || entrada.response 
    || entrada.result 
    || entrada.content 
    || "";

  if (typeof raw === "object" && raw !== null) {
    normalizado = raw;
  } else {
    raw = String(raw)
      .replace(/```json/g, "")
      .replace(/```/g, "")
      .trim();

    try {
      normalizado = JSON.parse(raw);
    } catch (error) {
      const match = raw.match(/\{[\s\S]*\}/);

      if (match) {
        try {
          normalizado = JSON.parse(match[0]);
        } catch (error2) {
          normalizado = null;
        }
      }
    }
  }
}

// ---------- 2. Traer datos originales de WhatsApp ----------
const variables = $("Variables3").first().json || {};

const instancia_ws = variables.instancia_ws || "";
const telefono = variables.telefono || "";
const id_mensaje = variables.id_mensaje || "";
const mensaje_usuario = variables.mensaje || "";

// ---------- 3. Traer metadatos de fecha desde Generar URLs ----------
let metaFecha = {};

try {
  metaFecha = $("Generar URLs SIPSA candidatas").first().json || {};
} catch (error) {
  metaFecha = {};
}

const modoBusquedaFecha = metaFecha.modo_busqueda_fecha || "mas_reciente";
const usuarioPidioFecha = metaFecha.fecha_solicitada === true;
const fechaSolicitadaLegible = metaFecha.fecha_legible_larga || metaFecha.fecha_legible || null;
const fechaSolicitadaISO = metaFecha.fecha_objetivo_iso || null;
const descripcionFechaSolicitada = metaFecha.descripcion_fecha_solicitada || null;

// ---------- 4. Funciones auxiliares ----------
function limpiarTexto(texto) {
  return String(texto || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}

function limpiarNombreProducto(nombre) {
  return String(nombre || "")
    .replace(/\*/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizarProducto(texto) {
  return String(texto || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\*/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function precioANumero(valor) {
  if (valor === null || valor === undefined || valor === "") {
    return null;
  }

  const texto = String(valor).trim().toLowerCase();

  if (
    texto === "n.d." ||
    texto === "n.d" ||
    texto === "-" ||
    texto.includes("no disponible")
  ) {
    return null;
  }

  const numero = Number(
    texto
      .replace(/\$/g, "")
      .replace(/\s/g, "")
      .replace(/\./g, "")
      .replace(",", ".")
  );

  return Number.isFinite(numero) ? Math.round(numero) : null;
}

function porcentajeANumero(valor) {
  if (valor === null || valor === undefined || valor === "") {
    return null;
  }

  const textoOriginal = String(valor).trim();
  const contieneSimboloPorcentaje = textoOriginal.includes("%");

  const texto = textoOriginal
    .toLowerCase()
    .replace("%", "")
    .replace(/\s/g, "")
    .replace(",", ".");

  if (
    texto === "n.d." ||
    texto === "n.d" ||
    texto === "-" ||
    texto.includes("no disponible")
  ) {
    return null;
  }

  let numero = Number(texto);

  if (!Number.isFinite(numero)) {
    return null;
  }

  // Si Excel entrega 4% como 0.04, lo convertimos a 4.
  if (!contieneSimboloPorcentaje && Math.abs(numero) > 0 && Math.abs(numero) <= 1) {
    numero = numero * 100;
  }

  return numero;
}

function formatearNumeroCOP(numero) {
  if (numero === null || numero === undefined || !Number.isFinite(numero)) {
    return "n.d.";
  }

  return Math.round(numero).toLocaleString("es-CO");
}

function formatearPrecioCOP(valor) {
  const numero = precioANumero(valor);

  if (numero === null) {
    return "n.d.";
  }

  return formatearNumeroCOP(numero);
}

function calcularVariacionPesosDesdeVar(precioActualRaw, varPorcentajeRaw) {
  const precioActual = precioANumero(precioActualRaw);
  const varPorcentaje = porcentajeANumero(varPorcentajeRaw);

  if (precioActual === null || varPorcentaje === null) {
    return null;
  }

  const factor = 1 + varPorcentaje / 100;

  if (!Number.isFinite(factor) || factor === 0) {
    return null;
  }

  const precioAnterior = precioActual / factor;
  const variacionPesos = precioActual - precioAnterior;

  return Math.round(variacionPesos);
}

function construirTextoVariacion(precioActualRaw, varPorcentajeRaw) {
  const variacionPesos = calcularVariacionPesosDesdeVar(precioActualRaw, varPorcentajeRaw);

  if (variacionPesos === null) {
    return `ℹ️ Variación: no disponible con respecto al día de mercado anterior.`;
  }

  const variacionAbs = formatearNumeroCOP(Math.abs(variacionPesos));

  if (variacionPesos > 0) {
    return `📈 Variación: subió *${variacionAbs} COP por kilogramo* con respecto al día de mercado anterior.`;
  }

  if (variacionPesos < 0) {
    return `📉 Variación: disminuyó *${variacionAbs} COP por kilogramo* con respecto al día de mercado anterior.`;
  }

  return `➡️ Variación: se mantuvo igual con respecto al día de mercado anterior.`;
}

