function obtenerFechaHoyColombia() {
  const partes = new Intl.DateTimeFormat("es-CO", {
    timeZone: "America/Bogota",
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(new Date());

  return {
    dia: Number(partes.find(p => p.type === "day").value),
    mes: Number(partes.find(p => p.type === "month").value),
    anio: Number(partes.find(p => p.type === "year").value)
  };
}

function parsearFechaReporte(textoFecha) {
  const texto = limpiarTexto(textoFecha);

  const meses = {
    "enero": 1,
    "febrero": 2,
    "marzo": 3,
    "abril": 4,
    "mayo": 5,
    "junio": 6,
    "julio": 7,
    "agosto": 8,
    "septiembre": 9,
    "setiembre": 9,
    "octubre": 10,
    "noviembre": 11,
    "diciembre": 12
  };

  const match = texto.match(/(\d{1,2})\s+de\s+([a-z]+)\s+de\s+(\d{4})/);

  if (!match) {
    return null;
  }

  const dia = Number(match[1]);
  const mesTexto = match[2];
  const anio = Number(match[3]);

  if (!meses[mesTexto]) {
    return null;
  }

  return {
    dia,
    mes: meses[mesTexto],
    anio
  };
}

