const TIEMPO_MAXIMO_MS = 20 * 60 * 1000;

// ---------- 2. Funciones auxiliares ----------
function limpiar(texto) {
  return String(texto || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\w\sñ]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function contextoVigente(contexto) {
  if (!contexto || !contexto.creado_en) return false;

  const edad = Date.now() - Number(contexto.creado_en);

  return edad >= 0 && edad <= TIEMPO_MAXIMO_MS;
}

function detectarRespuestaPapa(mensajeLimpio) {
  const palabras = mensajeLimpio.split(" ").filter(Boolean);

  if (palabras.includes("criolla")) {
    return "papa criolla";
  }

  if (palabras.includes("negra") || palabras.includes("negro")) {
    return "papa negra";
  }

  // Errores comunes
  if (mensajeLimpio.includes("nrgr") || mensajeLimpio.includes("negr")) {
    return "papa negra";
  }

  if (mensajeLimpio.includes("criol")) {
    return "papa criolla";
  }

  return null;
}

function detectarRespuestaPlatano(mensajeLimpio) {
  const palabras = mensajeLimpio.split(" ").filter(Boolean);

  if (palabras.includes("guineo")) {
    return "platano guineo";
