          mensaje_usuario_original,
          mensaje_usuario: mensajeConContexto,
          mensaje_limpio: limpiar(mensajeConContexto),

          es_producto_ambiguo: false,
          grupo_ambiguo: null,
          producto_resuelto_desde_contexto: true,
          producto_resuelto: productoResuelto,
          contexto_usado: true,

          respuesta_base: ""
        }
      }
    ];
  }
}

// ---------- 4. Detectar producto ambiguo en mensaje actual ----------
const palabrasRelleno = [
  "precio",
  "precios",
  "valor",
  "costo",
  "cuanto",
  "vale",
  "esta",
  "consultar",
  "consulta",
  "quiero",
  "quisiera",
  "saber",
  "del",
  "de",
  "la",
  "el",
  "un",
  "una",
  "por",
  "favor",
  "me",
  "puedes",
  "dar",
  "decir",
  "informar",
  "hoy",
  "ayer",
  "anteayer",
  "antier",
  "antes",
  "hace",
  "dias",
  "dia",
  "dos",
  "tres",
  "cuatro",
  "cinco",
  "seis",
  "siete",
  "ocho",
  "nueve",
  "diez",
  "lunes",
  "martes",
  "miercoles",
  "miércoles",
  "jueves",
  "viernes",
  "sabado",
  "sábado",
  "domingo",
  "pasado"
];

const palabras = mensajeActualLimpio.split(" ").filter(Boolean);
const palabrasProducto = palabras.filter(p => !palabrasRelleno.includes(p));
const textoProducto = palabrasProducto.join(" ");

// ---------- Papa ----------
const mencionaPapa = palabrasProducto.includes("papa");

const especificaPapa =
  palabrasProducto.includes("negra") ||
  palabrasProducto.includes("criolla");

const mencionaPapaNoDisponible =
  mencionaPapa &&
  (
    palabrasProducto.includes("pastusa") ||
    palabrasProducto.includes("pastosa")
  );

const esPapaAmbigua = mencionaPapa && !especificaPapa;

// ---------- Plátano ----------
const mencionaPlatano =
  palabrasProducto.includes("platano") ||
  palabrasProducto.includes("plátano");

const especificaPlatano =
  palabrasProducto.includes("guineo") ||
  palabrasProducto.includes("harton") ||
  palabrasProducto.includes("hartón") ||
  palabrasProducto.includes("verde");

const esPlatanoAmbiguo = mencionaPlatano && !especificaPlatano;

// ---------- 5. Construir respuesta ----------
let es_producto_ambiguo = false;
let grupo_ambiguo = null;
let respuesta_base = "";

if (mencionaPapaNoDisponible || esPapaAmbigua) {
  es_producto_ambiguo = true;
  grupo_ambiguo = "papa";

  staticData.contextos_ambiguos_mercoia[claveContexto] = {
    grupo_ambiguo,
    mensaje_original: mensaje_usuario_original,
    creado_en: Date.now()
  };

  respuesta_base = `🔎 Encontré más de una opción relacionada con papa.

¿Cuál precio deseas consultar?

🥔 Papa negra
🥔 Papa criolla

Puedes responder solo con una de las dos opciones.`;
}

else if (esPlatanoAmbiguo) {
  es_producto_ambiguo = true;
  grupo_ambiguo = "platano";

  staticData.contextos_ambiguos_mercoia[claveContexto] = {
    grupo_ambiguo,
    mensaje_original: mensaje_usuario_original,
    creado_en: Date.now()
  };

  respuesta_base = `🔎 Encontré más de una opción relacionada con plátano.

¿Cuál precio deseas consultar?

🍌 Plátano guineo
🍌 Plátano hartón verde

Puedes responder solo con una de las dos opciones.`;
}

// ---------- 6. Si no hay ambigüedad, limpiar contexto viejo ----------
if (!es_producto_ambiguo && contextoPendiente) {
  delete staticData.contextos_ambiguos_mercoia[claveContexto];
}

// ---------- 7. Salida ----------
return [
  {
    json: {
      ...entrada,
      instancia_ws,
      telefono,
      id_mensaje,

      mensaje_usuario_original,
      mensaje_usuario: mensaje_usuario_original,
      mensaje_limpio: mensajeActualLimpio,
      texto_producto_detectado: textoProducto,

      es_producto_ambiguo,
      grupo_ambiguo,
      producto_resuelto_desde_contexto: false,
      producto_resuelto: null,
      contexto_usado: false,

      respuesta_base
    }
  }
];
